#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=200210;
int n,len[N],l[N],r[N],ans;
string ss,s;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>ss;
	s=" #";
	n=1;
	for(int i=0;i<ss.size();i++)
	{
		n+=2;
		s+=ss[i];
		s+="#";
	}
	int mid=0,mx=0;
	for(int i=1;i<=n;i++)
	{
		if(i<mx) len[i]=min(mx-i,len[mid*2-i]);
		else len[i]=1;
		while(s[i+len[i]]==s[i-len[i]]) len[i]++;
		if(i+len[i]>mx)
		{
			mx=i+len[i];
			mid=i;
		}
		l[i+len[i]-1]=max(l[i+len[i]-1],len[i]-1);
		r[i-len[i]+1]=max(r[i-len[i]+1],len[i]-1);
	}
	for(int i=3;i<=n;i+=2)
	{
		r[i]=max(r[i],r[i-2]-2);
	}
	for(int i=n;i>=3;i-=2)
	{
		l[i]=max(l[i],l[i+2]-2);
	}
	for(int i=3;i<=n;i+=2)
	{
		if(r[i]>0&&l[i]>0) ans=max(ans,l[i]+r[i]);
	}
	cout<<ans;
	return 0;
}
